/**
 * Exam paper builder (teaching vault).
 *
 * This is the *printable exam* model: a teacher composes numbered questions of
 * several types, each written by hand or generated by AI from the subject's own
 * materials, and exports the result to Word/PDF. It is deliberately separate from
 * `studyAssessments.ts` — that one models an interactive test the student *takes*
 * (attempts, grading, correction mode); this one models a document that gets
 * printed, so it carries layout intent (answer lines, option columns, images) that
 * an on-screen quiz never needs.
 *
 * Everything here is pure and dependency-free so it can be unit-tested and shared by
 * the renderer (builder UI), the main process (export) and the AI generator.
 */

export const EXAM_QUESTION_TYPES = [
  'section',
  'short_essay',
  'medium_essay',
  'long_essay',
  'short_answer',
  'definition',
  'multiple_choice',
  'true_false',
  'matching',
  'ordering',
  'fill_blank',
  'image_comment',
  'problem',
] as const;

export type ExamQuestionType = (typeof EXAM_QUESTION_TYPES)[number];

/** The document's own language, independent from the interface language. */
export const EXAM_LANGUAGES = ['es', 'en', 'fr', 'de', 'pt', 'pt-BR'] as const;
export type ExamLanguage = (typeof EXAM_LANGUAGES)[number];

export interface ExamQuestionTypeDef {
  id: ExamQuestionType;
  /** Spanish source string, translated through t() in the UI. */
  label: string;
  description: string;
  icon: string;
  /** Blank ruled lines the printed paper leaves for the answer. */
  answerLines: number;
  defaultPoints: number;
  /** Needs a list of choices whose count the teacher sets. */
  needsOptions?: boolean;
  defaultOptionCount?: number;
  /** Needs left/right pairs to join with arrows. */
  needsPairs?: boolean;
  /** Needs an ordered list of items to sort. */
  needsItems?: boolean;
  /** Needs an embedded image to comment on. */
  needsImage?: boolean;
  /**
   * Not a question but a shared statement (a source text, a case, a picture) that
   * several sub-questions hang from. It takes no points of its own: its mark is the
   * sum of its sub-questions, so the two can never disagree on the printed paper.
   */
  isSection?: boolean;
  /** May carry an image even though it does not require one. */
  allowsImage?: boolean;
}

