/** At most two logos fit the header band without crowding the title. */
export const MAX_EXAM_LOGOS = 2;
/** Keeps a self-contained exam from bloating the vault database. */
export const MAX_EXAM_LOGO_BYTES = 512 * 1024;
export const MAX_EXAM_IMAGE_BYTES = 4 * 1024 * 1024;

export function defaultExamHeader(overrides: Partial<ExamHeaderConfig> = {}): ExamHeaderConfig {
  return {
    institution: '',
    subjectName: '',
    teachers: '',
    groupLabel: '',
    examTitle: '',
    dateText: '',
    durationMinutes: null,
    instructions: '',
    showStudentName: true,
    showStudentId: false,
    showGroup: true,
    showDate: true,
    showGradeBox: true,
    showPoints: true,
    ...overrides,
  };
}

/** A blank question of `type`, pre-filled with the shape that type requires. */
export function defaultExamQuestion(type: ExamQuestionType): ExamQuestionInput {
  const def = examQuestionTypeDef(type);
  const options: ExamOption[] = def.needsOptions
    ? Array.from({ length: def.defaultOptionCount ?? 4 }, (_, index) => ({ id: `O${index + 1}`, text: '', correct: index === 0 }))
    : [];
  const pairs: ExamPair[] = def.needsPairs
    ? Array.from({ length: 4 }, (_, index) => ({ id: `P${index + 1}`, left: '', right: '' }))
    : [];
  const items = def.needsItems ? ['', '', '', ''] : [];
  return {
    type,
    prompt: '',
    points: def.defaultPoints,
    options,
    pairs,
    items,
    imageDataUrl: null,
    imageCaption: '',
    answerLines: null,
    solution: '',
    aiPrompt: '',
    generatedBy: 'manual',
  };
}

/** Resize a multiple-choice question's option list, preserving what was typed. */
export function resizeExamOptions(options: ExamOption[], count: number): ExamOption[] {
  const target = Math.max(2, Math.min(10, Math.round(count)));
  const next = options.slice(0, target).map((option, index) => ({ ...option, id: `O${index + 1}` }));
  while (next.length < target) next.push({ id: `O${next.length + 1}`, text: '', correct: false });
  // A choice question with no marked answer would export an empty answer key.
  if (next.length && !next.some((option) => option.correct)) next[0] = { ...next[0], correct: true };
  return next;
}

/** Points are quarters at the finest, so two decimals always represent them exactly. */
function roundPoints(total: number): number {
  return Math.round(total * 100) / 100;
}

/**
 * The paper's total mark.
 *
 * Sections are skipped: a section's mark IS the sum of its sub-questions, so counting
 * both would double every grouped exercise.
 */
export function examTotalPoints(questions: Array<Pick<ExamQuestion, 'points' | 'type'>>): number {
  return roundPoints(
    questions.reduce(
      (sum, question) => (isExamSection(question.type) || !Number.isFinite(question.points) ? sum : sum + question.points),
      0
    )
  );
}

export interface ExamNumberedQuestion {
  question: ExamQuestion;
  /** `3` for a standalone question, `3.2` for the second one inside section 3. */
  number: string;
}

/**
 * One printed exercise: either a lone question, or a section statement with the
 * sub-questions that hang from it.
 */
export interface ExamBlock {
  /** The shared statement, or null when this block is a single top-level question. */
  section: ExamQuestion | null;
  /** The exercise number the paper prints (`1`, `2`, …). */
  number: string;
  questions: ExamNumberedQuestion[];
  /** What the exercise is worth: the sum of its sub-questions. */
  points: number;
}

/**
 * Turns the flat stored list into the nested structure everything renders from.
 *
 * Numbering is decided HERE and nowhere else, so the builder, the preview, the PDF, the
 * Word file and the answer key can never disagree about what "question 3.2" refers to.
 * Orphans (a sub-question whose section was deleted out from under it) are promoted to
 * top level rather than dropped, so no content can silently vanish from a paper.
 */
export function groupExamQuestions(questions: ExamQuestion[]): ExamBlock[] {
  const sorted = [...questions].sort((a, b) => a.position - b.position);
  const sectionIds = new Set(sorted.filter((question) => isExamSection(question.type)).map((question) => question.id));
  const childrenBySection = new Map<string, ExamQuestion[]>();
  for (const question of sorted) {
    if (isExamSection(question.type)) continue;
    if (question.parentId && sectionIds.has(question.parentId)) {
      const bucket = childrenBySection.get(question.parentId) ?? [];
      bucket.push(question);
      childrenBySection.set(question.parentId, bucket);
    }
  }

  const blocks: ExamBlock[] = [];
  let counter = 0;
  for (const question of sorted) {
    const isChild = !isExamSection(question.type) && question.parentId != null && sectionIds.has(question.parentId);
    if (isChild) continue;
    counter += 1;
    const number = String(counter);
    if (isExamSection(question.type)) {
      const children = childrenBySection.get(question.id) ?? [];
      blocks.push({
        section: question,
        number,
        questions: children.map((child, index) => ({ question: child, number: `${number}.${index + 1}` })),
        points: examTotalPoints(children),
      });
    } else {
      blocks.push({ section: null, number, questions: [{ question, number }], points: examTotalPoints([question]) });
    }
  }
  return blocks;
}

/** Every question in printing order, paired with the number the paper shows. */
export function flattenExamBlocks(blocks: ExamBlock[]): ExamNumberedQuestion[] {
  return blocks.flatMap((block) => block.questions);
}

/**
 * Split `total` across `count` sub-questions in quarter-point steps, giving the
 * remainder to the first ones — so 5 points over 3 questions reads 1.75 / 1.75 / 1.5
 * rather than 1.6666 repeating, which no teacher would write on a paper.
 */
export function distributeSectionPoints(total: number, count: number): number[] {
  if (count <= 0) return [];
  // A non-finite total is an empty or half-typed field, not a request to zero the
  // exercise: `Math.max(0, NaN)` is NaN, and it propagated into every sub-question.
  if (!Number.isFinite(total)) return [];
  const quarters = Math.max(0, Math.round(total * 4));
  const base = Math.floor(quarters / count);
  const remainder = quarters - base * count;
  return Array.from({ length: count }, (_, index) => (base + (index < remainder ? 1 : 0)) / 4);
}

/** Ruled lines the printed paper leaves for a question. */
export function examAnswerLines(question: Pick<ExamQuestion, 'type' | 'answerLines'>): number {
  if (question.answerLines != null && Number.isFinite(question.answerLines)) return Math.max(0, Math.min(40, Math.round(question.answerLines)));
  return examQuestionTypeDef(question.type).answerLines;
}

export function renumberExamQuestions<T extends { position: number }>(questions: T[]): T[] {
  return questions.map((question, index) => ({ ...question, position: index }));
}

/** Move a question and return the reordered ids, for the repo to persist. */
export function moveExamQuestion(ids: string[], from: number, to: number): string[] {
  if (from < 0 || from >= ids.length) return ids.slice();
  const target = Math.max(0, Math.min(ids.length - 1, to));
  const next = ids.slice();
  const [moved] = next.splice(from, 1);
  next.splice(target, 0, moved);
  return next;
}

export interface ExamIssue {
  questionId?: string;
  field: 'subject' | 'prompt' | 'options' | 'pairs' | 'items' | 'image' | 'count' | 'points' | 'section';
  /** Spanish source string, translated through t() in the UI. */
  message: string;
}

/**
 * Everything that would make the exported paper wrong or unusable. The builder shows
 * these inline and blocks export until they're clear, so a teacher never prints a
 * question with empty options or a missing image.
 */
export function validateExam(exam: TeachingExam, questions: ExamQuestion[]): ExamIssue[] {
  const issues: ExamIssue[] = [];
  if (!exam.subjectId) issues.push({ field: 'subject', message: 'Elige la asignatura del examen.' });
  if (!questions.length) issues.push({ field: 'count', message: 'Añade al menos una pregunta.' });
  // A section with nothing under it prints a statement nobody is asked to answer.
  for (const block of groupExamQuestions(questions)) {
    if (block.section && !block.questions.length) {
      issues.push({ questionId: block.section.id, field: 'section', message: 'Añade al menos una pregunta dentro del enunciado.' });
    }
  }
  for (const question of questions) {
    const def = examQuestionTypeDef(question.type);
    if (!question.prompt.trim()) issues.push({ questionId: question.id, field: 'prompt', message: 'Escribe el enunciado o genéralo con IA.' });
    // A section carries no mark of its own, so there is nothing to check.
    if (def.isSection) continue;
    if (!Number.isFinite(question.points) || question.points < 0) issues.push({ questionId: question.id, field: 'points', message: 'La puntuación debe ser un número positivo.' });
    if (def.needsOptions) {
      const filled = question.options.filter((option) => option.text.trim());
      if (filled.length < 2) issues.push({ questionId: question.id, field: 'options', message: 'Escribe al menos dos opciones.' });
    }
    if (def.needsPairs) {
      const filled = question.pairs.filter((pair) => pair.left.trim() && pair.right.trim());
      if (filled.length < 2) issues.push({ questionId: question.id, field: 'pairs', message: 'Escribe al menos dos parejas para relacionar.' });
    }
    if (def.needsItems) {
      const filled = question.items.filter((item) => item.trim());
      if (filled.length < 2) issues.push({ questionId: question.id, field: 'items', message: 'Escribe al menos dos elementos para ordenar.' });
    }
    if (def.needsImage && !question.imageDataUrl) issues.push({ questionId: question.id, field: 'image', message: 'Inserta la imagen que hay que comentar.' });
  }
  return issues;
}

/**
 * Labels printed on the document. These follow the EXAM's language, not the
 * interface language: a teacher with an English UI still prints a Spanish exam.
 * Kept as in-data tables (not i18n keys) for exactly that reason.
 */
